25	// pin down the exact value written to each output pointer.
26	#define COLOR_SCHEMES_TABLE ((const uint8_t[4][32]){ \
27		{8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0}, \
