56	// Powers of ten as 64-bit constants, indexed 0..10. Used by the getDigitCount
57	// contract to pin down the returned digit count without overflow (10^10 does
58	// not fit in uint32_t).
59	#define DC_POW10(k) (((const uint64_t[]){ \
60		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, \
61		1000000ULL, 10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL})[(k)])
62	
63	uint8_t getDigitCount(uint32_t number)
64	// the count of decimal digits of a uint32_t is between 1 (for 0..9) and 10
65	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
66	// the result d is the unique value with number < 10^d ...
67	__CPROVER_ensures((uint64_t)number < DC_POW10((int)__CPROVER_return_value))
68	// ... and number >= 10^(d-1), except 0 (which has no nonzero leading digit)
69	__CPROVER_ensures(__CPROVER_return_value == 1 || (uint64_t)number >= DC_POW10((int)__CPROVER_return_value - 1))
70	{
71		uint8_t count = 0;
72		do
73		{
74			number /= 10;
75			count += 1;
76		} while (number);
77		return count;
78	}
