209	void rotateBoard(uint8_t board[SIZE][SIZE])
210	{
211		uint8_t i, j, n = SIZE;
212		uint8_t tmp;
213		for (i = 0; i < n / 2; i++)
214		{
215			for (j = i; j < n - i - 1; j++)
216			{
217				tmp = board[i][j];
218				board[i][j] = board[j][n - i - 1];
219				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
220				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
221				board[n - j - 1][i] = tmp;
222			}
223		}
224	}
