270	bool findPairDown(uint8_t board[SIZE][SIZE])
271	{
272		bool success = false;
273		uint8_t x, y;
274		for (x = 0; x < SIZE; x++)
275		{
276			for (y = 0; y < SIZE - 1; y++)
277			{
278				if (board[x][y] == board[x][y + 1])
279					return true;
280			}
281		}
282		return success;
283	}
