285	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
286	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
287	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
288	// CBMC pins down the precise count (not just a bound), killing mutations of the
289	// comparison, the increment, and the loop bounds.
290	#define CE_TOTAL ( \
291		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
292		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
293		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
294		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
295	
296	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
297	// clang-format off
298	// the board must be a readable 4x4 block of bytes
299	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
300	// countEmpty only reads the board; it writes nothing
301	__CPROVER_assigns()
302	// the result is exactly the number of empty (zero-valued) cells
303	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
304	// clang-format on
305	{
306		uint8_t x, y;
307		uint8_t count = 0;
308		for (x = 0; x < SIZE; x++)
309		{
310			for (y = 0; y < SIZE; y++)
311			{
312				if (board[x][y] == 0)
313				{
314					count++;
315				}
316			}
317		}
318		return count;
319	}
