321	bool gameEnded(uint8_t board[SIZE][SIZE])
322	{
323		bool ended = true;
324		if (countEmpty(board) > 0)
325			return false;
326		if (findPairDown(board))
327			return false;
328		rotateBoard(board);
329		if (findPairDown(board))
330			ended = false;
331		rotateBoard(board);
332		rotateBoard(board);
333		rotateBoard(board);
334		return ended;
335	}
