337	// Stub for srand: it has no observable effect for verification purposes.
338	void srand(unsigned int seed) { (void)seed; }
339	
340	// Helper macro for addRandom's postcondition.
341	//
342	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
343	// bound. The full collection loop in addRandom is long enough that its complete
344	// path exceeds that bound, so the postcondition is only ever *reached* on
345	// shorter paths (e.g. mutants that disable the scan loops and leave the board
346	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
347	// so a relational "some cell changed" postcondition becomes unreachable too.
348	// The postcondition below is therefore phrased purely over the post-state (no
349	// history), keeping it cheap enough to be reached on those shorter paths.
350	// After addRandom the board always has at least one non-empty cell: if it had
351	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
352	// already full, every cell stays non-empty. A mutant that disables the scan
353	// loops leaves an all-empty input board untouched and violates this. The
354	// property is phrased as a single existential over the flat 16-byte board so
355	// it stays cheap in the shallow depth budget (see note above).
356	#define AR_SOME_NONEMPTY                                  \
357		__CPROVER_exists                                      \
358		{                                                    \
359			int _k;                                          \
360			(0 <= _k && _k < SIZE *SIZE) &&                  \
361				((uint8_t *)board)[_k] != 0                  \
362		}
363	
364	void addRandom(uint8_t board[SIZE][SIZE])
365	// clang-format off
366	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
367	__CPROVER_assigns(__CPROVER_object_whole(board))
368	__CPROVER_ensures(AR_SOME_NONEMPTY)
369	// clang-format on
370	{
371		static bool initialized = false;
372		uint8_t x, y;
373		uint8_t r, len = 0;
374		uint8_t n, list[SIZE * SIZE][2];
375	
376		if (!initialized)
377		{
378			srand(time(NULL));
379			initialized = true;
380		}
381	
382		for (x = 0; x < SIZE; x++)
383		{
384			for (y = 0; y < SIZE; y++)
385			{
386				if (board[x][y] == 0)
387				{
388					list[len][0] = x;
389					list[len][1] = y;
390					len++;
391				}
392			}
393		}
394	
395		if (len > 0)
396		{
397			r = rand() % len;
398			x = list[r][0];
399			y = list[r][1];
400			n = (rand() % 10) / 9 + 1;
401			board[x][y] = n;
402		}
403	}
