419	void setBufferedInput(bool enable)
420	{
421		static bool enabled = true;
422		static struct termios old;
423		struct termios new;
424	
425		if (enable && !enabled)
426		{
427			// restore the former settings
428			tcsetattr(STDIN_FILENO, TCSANOW, &old);
429			// set the new state
430			enabled = true;
431		}
432		else if (!enable && enabled)
433		{
434			// get the terminal settings for standard input
435			tcgetattr(STDIN_FILENO, &new);
436			// we want to keep the old setting to restore them at the end
437			old = new;
438			// disable canonical mode (buffered i/o) and local echo
439			new.c_lflag &= (~ICANON & ~ECHO);
440			// set the new settings immediately
441			tcsetattr(STDIN_FILENO, TCSANOW, &new);
442			// set the new state
443			enabled = false;
444		}
445	}
