447	bool testSucceed()
448	{
449		uint8_t array[SIZE];
450		// these are exponents with base 2 (1=2 2=4 3=8)
451		// data holds per line: 4x IN, 4x OUT, 1x POINTS
452		uint8_t data[] = {
453			0, 0, 0, 1, 1, 0, 0, 0, 0,
454			0, 0, 1, 1, 2, 0, 0, 0, 4,
455			0, 1, 0, 1, 2, 0, 0, 0, 4,
456			1, 0, 0, 1, 2, 0, 0, 0, 4,
457			1, 0, 1, 0, 2, 0, 0, 0, 4,
458			1, 1, 1, 0, 2, 1, 0, 0, 4,
459			1, 0, 1, 1, 2, 1, 0, 0, 4,
460			1, 1, 0, 1, 2, 1, 0, 0, 4,
461			1, 1, 1, 1, 2, 2, 0, 0, 8,
462			2, 2, 1, 1, 3, 2, 0, 0, 12,
463			1, 1, 2, 2, 2, 3, 0, 0, 12,
464			3, 0, 1, 1, 3, 2, 0, 0, 4,
465			2, 0, 1, 1, 2, 2, 0, 0, 4};
466		uint8_t *in, *out, *points;
467		uint8_t t, tests;
468		uint8_t i;
469		bool success = true;
470		uint32_t score;
471	
472		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
473		for (t = 0; t < tests; t++)
474		{
475			in = data + t * (2 * SIZE + 1);
476			out = in + SIZE;
477			points = in + 2 * SIZE;
478			for (i = 0; i < SIZE; i++)
479			{
480				array[i] = in[i];
481			}
482			score = 0;
483			slideArray(array, &score);
484			for (i = 0; i < SIZE; i++)
485			{
486				if (array[i] != out[i])
487				{
488					success = false;
489				}
490			}
491			if (score != *points)
492			{
493				success = false;
494			}
495			if (success == false)
496			{
497				for (i = 0; i < SIZE; i++)
498				{
499					printf("%u ", in[i]);
500				}
501				printf("=> ");
502				for (i = 0; i < SIZE; i++)
503				{
504					printf("%u ", array[i]);
505				}
506				printf("(%u points) expected ", score);
507				for (i = 0; i < SIZE; i++)
508				{
509					printf("%u ", in[i]);
510				}
511				printf("=> ");
512				for (i = 0; i < SIZE; i++)
513				{
514					printf("%u ", out[i]);
515				}
516				printf("(%u points)\n", *points);
517				break;
518			}
519		}
520		if (success)
521		{
522			printf("All %u tests executed successfully\n", tests);
523		}
524		return success;
525	}
