591		signal(SIGINT, signal_callback_handler);
592	
593		initBoard(board);
594		setBufferedInput(false);
595		drawBoard(board, scheme, score);
596		while (true)
597		{
598			c = getchar();
599			if (c == EOF)
600			{
601				puts("\nError! Cannot read keyboard input!");
602				break;
603			}
604			switch (c)
605			{
606			case 52:  // '4' key
607			case 97:  // 'a' key
